module hmac(
    input wire clk,
    input wire rst,
    input wire [7:0] key,
    input wire [7:0] message,
    output reg [7:0] hmac_out
);
    reg [7:0] secret_key;
    reg [7:0] message_reg;
    reg [7:0] hash_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            secret_key <= 8'b0;
            message_reg <= 8'b0;
            hash_reg <= 8'b0;
            hmac_out <= 8'b0;
        end else begin
            secret_key <= key;
            message_reg <= message;
            hash_reg <= secret_key ^ message_reg; // Simple hash function using XOR
            hmac_out <= hash_reg; // Output the computed HMAC
        end
    end
endmodule
